/**
 * @summary Fetch patient health history via ABDM integration
 */
export const getGetPatientHistoryUrl = (params: GetPatientHistoryParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/healthcare/patient-history?${stringifiedParams}`
    : `/api/healthcare/patient-history`;
};

export const getPatientHistory = async (
  params: GetPatientHistoryParams,
  options?: RequestInit,
): Promise<PatientHistory> => {
  return customFetch<PatientHistory>(getGetPatientHistoryUrl(params), {
    ...options,
    method: "GET",
  });
};

